mapper.select:
SELECT C.CMNT_NO AS cmntNo, C.CMNT_COMM_NO AS commNo, CM.COMM_TITLE AS commTitle, C.CMNT_MBR_ID AS cmntMbrId, M.MBR_NICKNAME AS nickname, C.CMNT_CONTENT AS cmntContent, DATE_FORMAT(C.CMNT_REG_DATE, '%Y-%m-%d %H:%i') AS cmntRegDate, C.CMNT_USE_YN AS cmntUseYn FROM COMMENT C JOIN MEMBER M ON C.CMNT_MBR_ID = M.MBR_ID JOIN COMMUNITY CM ON C.CMNT_COMM_NO = CM.COMM_NO
C.CMNT_USE_YN = 'N' 1=1 C.CMNT_USE_YN = 'Y'
ORDER BY C.CMNT_NO DESC LIMIT #{offset}, #{size}

mapper.update:
UPDATE COMMUNITY
SET COMM_CMNT_CNT = COMM_CMNT_CNT + 1
WHERE COMM_NO = #{commNo}
